var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"......왔군.","JPN":"……来たな。","ENG":"You're here.","TWN":"……來了。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"너희들의 상대는 나다.","JPN":"貴様らの相手は、この私だ。","ENG":"I'll be dealing with you.","TWN":"你們的對手是我。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......리플레이서 나이트.","JPN":"……リプレイサー・ナイト。","ENG":"Replacer Knight.","TWN":"……克隆．騎士。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 혼자서 나오다니, 아무리 그래도 우릴 너무 무시하는 거 아냐?","JPN":"いくらなんでも一人で来るなんて、アタシたちを見くびるにもほどがあるわね。","ENG":"You're out here alone? This is almost insulting.","TWN":"但妳竟然敢一個人出來，不管怎麼樣，這也太不把我們放在眼裡了吧？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지난번에는 한 방 먹었지만, 이번엔 그렇게 호락호락하지 않을걸?","JPN":"前回は一杯食わされたけど、今回はそう簡単にはいかないわよ？","ENG":"You got me good last time, but it won't be so easy this time around.","TWN":"上次我們雖然被擺了一道，但這次我們可不會這麼好欺負了。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"바보 같은 소릴 하는군.","JPN":"バカなことを言うな。","ENG":"You're being absurd.","TWN":"說什麼蠢話。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"한때나마 <color=#ffd34c>왕</color>의 동료였던 자들을 상대로 여유부릴 생각은 없다.","JPN":"一時ではあるが、<color=#ffd34c>王</color>の仲間だった者を相手に、余裕ではいられない。","ENG":"I have no intention of taking you lightly. You were once colleagues of <color=#ffd34c>King</color>.","TWN":"對付<color=#ffd34c>王</color>曾經的同伴，我可不覺得自己會有什麼餘裕。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"KNIGHT_REPLACER_REGEN_NULL","text":{"KOREA":"다만 테라사이드 시스템의 수호자로서 내 의무에 충실할 뿐이다.","JPN":"私は、テラサイドシステムの守護者としての義務を果たすだけだ。","ENG":"I'm just sticking to my duty as the guardian of System Terraside.","TWN":"作為特拉賽德系統的守護者，我只是恪守我的任務而已。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"주의하십시오, 중장님.","JPN":"お気を付けください、中将。","ENG":"Be careful, Lieutenant General.","TWN":"請您小心，中將大人。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"저 자가 바로 KS-1 도시관리국의 배신 사건을 주도한 장본인입니다.","JPN":"あの者こそが、KS-1都市管理局の事件を主導した張本人です。","ENG":"That's the mastermind behind the betrayals of KS-1 City Management.","TWN":"她就是主導KS-1城市管理局叛亂事件的本人。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"나도 보고는 받았네, 카일.","JPN":"私も報告は受けているよ、カイル。","ENG":"So I've been told, Kyle.","TWN":"我收到報告了，凱爾。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"하지만 보고서 내용에 있던 것과는 조금 다르군.","JPN":"だが、報告書の内容とは少しズレがあるな。","ENG":"But she seems a little bit different than how she was described in the reports.","TWN":"但和報告裡的內容有點不一樣啊。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"보고서에는 훨씬 더 공격적인 성격이라고 나와 있던 것 같은데?","JPN":"報告書には、あれよりも遥かに攻撃的な性格だと書かれていたような気がするが？","ENG":"I thought she'd be much more aggressive than this.","TWN":"報告裡好像說她具有更強烈的攻擊性格？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"관리국에서 제공한 정보에 따르면 저 자는 이전의 <color=#ffd34c>리플레이서 나이트</color>를 기반으로 하여 새롭게 만들어진 <color=#ffd34c>진화 재생체</color>라고 합니다.","JPN":"管理局提供の情報によると、あの者は以前の<color=#ffd34c>リプレイサー・ナイト</color>を\\nもとに新しく作られた<color=#ffd34c>進化再生体</color>だそうです。","ENG":"According to the intel from the Administration, she's a <color=#ffd34c>Regenerated Replacer</color> newly built from the bioinformation of the <color=#ffd34c>Replacer Knight</color>.","TWN":"根據管理局提供的情報，那個人是以過去的<color=#ffd34c>克隆．騎士</color>為基礎，被重新創造出來的 <color=#ffd34c>進化再生體</color>。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"성격은 물론 전투 능력도 이전과는 비교할 수 없을 정도로 상승했을 것으로 추정됩니다.","JPN":"性格の変化はもちろん、戦闘能力も以前とは比べ物にならないほど上昇しているとみられます。","ENG":"We're assuming that her personality has gone through considerable changes, just like her combat abilities have.","TWN":"不只是性格，推測她連戰鬥能力都上升到了以前無法比擬的程度。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":null,"C":{"char_id":"KNIGHT_REPLACER_REGEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"......흥미롭군.","JPN":"……興味深いな。","ENG":"Interesting.","TWN":"……真有趣呢。"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"관리국 최고관리위원회는 대체 어떻게 그런 정보를 다 알고 있는 걸까?","JPN":"管理局の最高管理委員会は、いったいどうやってその手の情報を入手したのだろうな？","ENG":"How does the Administration High Committee know all this?","TWN":"管理局最高管理委員會到底是怎麼知道這些事情的啊？"},"stage":{"bg":"COUNTERSIDE_RED","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};